Sure! Here's an example of how you can read the SSL protocol version from configuration and apply it to an ASP.NET Core server:

1. First, make sure you have the following NuGet packages installed in your project:
   - Microsoft.Extensions.Configuration
   - Microsoft.Extensions.Configuration.Json
   - Microsoft.AspNetCore.Server.Kestrel.Https

2. Create a JSON configuration file (e.g., "appsettings.json") with the SSL protocol version setting:
   ```json
   {
     "SSLProtocolVersion": "Tls12"
   }
   ```

3. In your `Startup.cs` file, add the following code to configure the SSL protocol version:
   ```csharp
   using Microsoft.AspNetCore.Builder;
   using Microsoft.AspNetCore.Hosting;
   using Microsoft.AspNetCore.Server.Kestrel;
   using Microsoft.Extensions.Configuration;
   using Microsoft.Extensions.DependencyInjection;

   public class Startup
   {
       public Startup(IConfiguration configuration)
       {
           Configuration = configuration;
       }

       public IConfiguration Configuration { get; }

       public void ConfigureServices(IServiceCollection services)
       {
           services.Configure<KestrelServerOptions>(Configuration.GetSection("Kestrel"));
       }

       public void Configure(IApplicationBuilder app, IWebHostEnvironment env)
       {
           var serverOptions = app.ApplicationServices.GetRequiredService<IOptions<KestrelServerOptions>>().Value;

           var sslProtocolVersion = Configuration["SSLProtocolVersion"];
           if (!string.IsNullOrEmpty(sslProtocolVersion))
           {
               serverOptions.ConfigureHttpsDefaults(httpsOptions =>
               {
                   // Set the SSL protocol version
                   httpsOptions.SslProtocols = Enum.Parse<SslProtocols>(sslProtocolVersion, ignoreCase: true);
               });
           }

           // Other configurations...

           app.UseRouting();
           // Other middleware and endpoints...
       }
   }
   ```

4. In the `ConfigureServices` method, we're configuring the `KestrelServerOptions` using the "Kestrel" section from the configuration. This is optional but allows you to configure other Kestrel options if needed.

5. In the `Configure` method, we retrieve the SSL protocol version from the configuration and apply it to the Kestrel server options using the `ConfigureHttpsDefaults` method.

The server will now use the SSL protocol version specified in the configuration file. Make sure to replace "Tls12" with the appropriate SSL protocol version you want to use, such as "Tls11" or "Tls13".

