public static IHostBuilder CreateHostBuilder(string[] args) =>
    Host.CreateDefaultBuilder(args)
        .ConfigureWebHostDefaults(webBuilder =>
        {
            webBuilder.UseKestrel((hostingContext, kestrelOptions) =>
            {
                var configuration = hostingContext.Configuration;
                var sslProtocolVersions = configuration.GetSection("SSLProtocolVersions").Get<string[]>();

                if (sslProtocolVersions != null && sslProtocolVersions.Length > 0)
