Apologies for the confusion. It seems there was a mistake in the original code provided. The correct method to set the SSL protocol versions for Kestrel in ASP.NET Core is `ConfigureHttpsDefaults`. However, this method is not directly available on the `httpsOptions` object.

To set the SSL protocol versions for Kestrel, you can use the `Protocols` property on the `httpsOptions.ListenOptions` object. Here's the updated code:

```csharp
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Server.Kestrel.Core;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;

public class Startup
{
    public Startup(IConfiguration configuration)
    {
        Configuration = configuration;
    }

    public IConfiguration Configuration { get; }

    public void ConfigureServices(IServiceCollection services)
    {
        services.Configure<SSLProtocolOptions>(Configuration.GetSection("SSLProtocolOptions"));
    }

    public void Configure(IApplicationBuilder app, IWebHostEnvironment env)
    {
        var serverOptions = app.ApplicationServices.GetRequiredService<KestrelServerOptions>();
        var sslProtocolOptions = Configuration.GetSection("SSLProtocolOptions").Get<SSLProtocolOptions>();

        if (sslProtocolOptions != null && sslProtocolOptions.SSLProtocolVersions != null && sslProtocolOptions.SSLProtocolVersions.Length > 0)
        {
            var protocols = sslProtocolOptions.SSLProtocolVersions
                .Select(v => Enum.Parse<Microsoft.AspNetCore.Server.Kestrel.Https.HttpsProtocols>(v, ignoreCase: true));

            foreach (var protocol in protocols)
            {
                serverOptions.ConfigureHttpsDefaults(listenOptions =>
                {
                    listenOptions.Protocols = protocol;
                });
            }
        }

        // Other configurations...

        app.UseRouting();
        // Other middleware and endpoints...
    }
}
```

In this updated code, we iterate over the SSL protocol versions and configure each protocol using `serverOptions.ConfigureHttpsDefaults`. Each `listenOptions` object passed into `ConfigureHttpsDefaults` has a `Protocols` property that can be set with the desired protocol value.

